    public static void main(String[] args) throws IOException {

        // 设置请求头信息，其中“User-Agent”为必填参数
        String userAgent = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) " +
                "Chrome/92.0.4515.131 Safari/537.36 Edg/92.0.902.67";
        String url = "https://huggingface.co/spaces/yuntian-deng/ChatGPT";

        // 创建OkHttpClient实例并发送HTTP GET请求
        OkHttpClient client = new OkHttpClient().newBuilder().build();
        Request request = new Request.Builder()
                .url(url)
                .addHeader("User-Agent", userAgent)
                .build();
        Response response = client.newCall(request).execute();

        // 获取响应HTML文本并进行解析
        String htmlString = response.body().string();    
        // 在此对获取到的HTML页面进行解析、提取信息等操作
        System.out.print(htmlString);   
    }
}
```

